45	
46	  /**
47	   * Creates an OpenAI responses API model for text generation.
48	   */
49	  responses(modelId: OpenAIResponsesModelId): LanguageModelV3;
50	
51	  /**
52	   * Creates an OpenAI completion model for text generation.
53	   */
