  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'LUMA_API_KEY',
          description: 'Luma',
        })}`,
        ...options.headers,
      },
      `ai-sdk/luma/${VERSION}`,
    );

  return {
    specificationVersion: 'v3' as const,
    image: (modelId) => new LumaImageModel(modelId, { /* ... */ }),
    imageModel: (modelId) => new LumaImageModel(modelId, { /* ... */ }),
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
    },
    embeddingModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
    },
  };
}

export const luma = createLuma();
```

**Key interfaces from `@ai-sdk/provider`:**
- `ProviderV3` - Base provider interface
- `ImageModelV3`, `LanguageModelV3`, `EmbeddingModelV3`, etc. - Model interfaces
- `NoSuchModelError` - Error for unsupported model types

