import { NoSuchModelError } from '@ai-sdk/provider';
import { beforeEach, describe, expect, it, vi } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';
import { createPixelArt } from './pixelart-provider';

vi.mock('./pixelart-image-model', () => ({
  PixelArtImageModel: vi.fn(),
}));

describe('createPixelArt', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe('image', () => {
    it('should construct an image model with default configuration', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const modelId = 'pixelart-v1';

      const model = provider.image(modelId);

      expect(model).toBeInstanceOf(PixelArtImageModel);
      expect(PixelArtImageModel).toHaveBeenCalledWith(
        modelId,
        expect.objectContaining({
          provider: 'pixelart.image',
          baseURL: 'https://api.pixelart.ai/v1',
        }),
      );
    });

    it('should respect custom configuration options', () => {
      const customBaseURL = 'https://custom.pixelart.ai/v1';
      const customHeaders = { 'X-Custom-Header': 'value' };
      const mockFetch = vi.fn();

      const provider = createPixelArt({
        apiKey: 'custom-api-key',
        baseURL: customBaseURL,
        headers: customHeaders,
        fetch: mockFetch,
      });
      const modelId = 'pixelart-v1';

      provider.image(modelId);

      expect(PixelArtImageModel).toHaveBeenCalledWith(
        modelId,
        expect.objectContaining({
          baseURL: customBaseURL,
          headers: expect.any(Function),
          fetch: mockFetch,
          provider: 'pixelart.image',
        }),
      );
    });

    it('imageModel should be an alias for image', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const modelId = 'pixelart-v1';

      provider.imageModel(modelId);

      expect(PixelArtImageModel).toHaveBeenCalledWith(
        modelId,
        expect.objectContaining({ provider: 'pixelart.image' }),
      );
    });
  });

  describe('languageModel', () => {
    it('should throw NoSuchModelError', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      expect(() => provider.languageModel('some-model')).toThrow(
        NoSuchModelError,
      );
    });
  });

  describe('embeddingModel', () => {
    it('should throw NoSuchModelError', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      expect(() => provider.embeddingModel('some-model')).toThrow(
        NoSuchModelError,
      );
    });
  });

  describe('textEmbeddingModel', () => {
    it('should throw NoSuchModelError', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      expect(() => provider.textEmbeddingModel('some-model')).toThrow(
        NoSuchModelError,
      );
    });
  });
});

